/* ══ WORLD MAP ══ */
const IMG_W = 1280,
  IMG_H = 800,
  MIN_WZ = 1,
  MAX_WZ = 4;
function coverZoom() {
  const c = document.getElementById("worldCanvas");
  return Math.max(c.clientWidth / IMG_W, c.clientHeight / IMG_H);
}
function clampWPan(x, y, z) {
  const c = document.getElementById("worldCanvas");
  const sw = IMG_W * z,
    sh = IMG_H * z;
  const mx = Math.max(0, (sw - c.clientWidth) / 2),
    my = Math.max(0, (sh - c.clientHeight) / 2);
  return {
    x: Math.max(-mx, Math.min(mx, x)),
    y: Math.max(-my, Math.min(my, y)),
  };
}
function applyW() {
  document.getElementById("worldInner").style.transform =
    `translate(${S.wPan.x}px,${S.wPan.y}px) scale(${S.wZoom})`;
}
function centerWorld() {
  S.wZoom = coverZoom();
  S.wPan = { x: 0, y: 0 };
  applyW();
}
function animZoomTo(px, py, dur = 900) {
  const cz = coverZoom();
  const tz = Math.min(MAX_WZ, cz * 2.2);
  const tx = -(px / 100 - 0.5) * IMG_W * tz,
    ty = -(py / 100 - 0.5) * IMG_H * tz;
  const tp = clampWPan(tx, ty, tz);
  const sz = S.wZoom,
    sp = { ...S.wPan },
    t0 = performance.now();
  const ease = (t) => (t < 0.5 ? 2 * t * t : -1 + (4 - 2 * t) * t);
  (function step(now) {
    const t = Math.min(1, (now - t0) / dur),
      et = ease(t);
    S.wZoom = sz + (tz - sz) * et;
    S.wPan.x = sp.x + (tp.x - sp.x) * et;
    S.wPan.y = sp.y + (tp.y - sp.y) * et;
    applyW();
    if (t < 1) requestAnimationFrame(step);
  })(t0);
}

function buildWorld() {
  const inner = document.getElementById("worldInner");
  inner.querySelectorAll(".dmarker").forEach((e) => e.remove());
  DISTRICTS.forEach((d, i) => {
    const m = document.createElement("div");
    m.className = "dmarker";
    m.style.cssText = `left:${d.px}%;top:${d.py}%;animation-duration:${3 + i * 0.35}s;animation-delay:${i * 0.2}s;`;
    m.innerHTML = `<div class="mbubble">${d.emoji}</div><div class="mtip"></div><div class="mlabel"><span class="mlname">${d.name}</span></div>`;
    m.addEventListener("click", (e) => enterDistrict(d, e));
    m.style.opacity = "0";
    inner.appendChild(m);
    setTimeout(
      () => {
        m.style.transition = "opacity .5s";
        m.style.opacity = "1";
      },
      150 + i * 110,
    );
  });
  centerWorld();
  setTimeout(() => animZoomTo(47, 40), 500);
}

/* World drag */
const wC = document.getElementById("worldCanvas");
wC.addEventListener("mousedown", (e) => {
  if (e.target.closest(".dmarker")) return;
  S.wDrag = true;
  S.wDs = { x: e.clientX, y: e.clientY };
  S.wPs = { ...S.wPan };
  wC.style.cursor = "grabbing";
  e.preventDefault();
});
window.addEventListener("mousemove", (e) => {
  if (!S.wDrag) return;
  const r = clampWPan(
    S.wPs.x + (e.clientX - S.wDs.x),
    S.wPs.y + (e.clientY - S.wDs.y),
    S.wZoom,
  );
  S.wPan = r;
  applyW();
});
window.addEventListener("mouseup", () => {
  S.wDrag = false;
  wC.style.cursor = "grab";
});
wC.addEventListener(
  "wheel",
  (e) => {
    e.preventDefault();
    const cz = coverZoom();
    const nz = Math.max(cz, Math.min(MAX_WZ, S.wZoom * (1 - e.deltaY * 0.001)));
    const canvas = document.getElementById("worldCanvas");
    const rect = canvas.getBoundingClientRect();
    const mx = e.clientX - rect.left - rect.width / 2,
      my = e.clientY - rect.top - rect.height / 2;
    const ix = (mx - S.wPan.x) / S.wZoom,
      iy = (my - S.wPan.y) / S.wZoom;
    const np = clampWPan(mx - ix * nz, my - iy * nz, nz);
    S.wZoom = nz;
    S.wPan = np;
    applyW();
  },
  { passive: false },
);
wC.addEventListener(
  "touchstart",
  (e) => {
    if (e.touches.length === 1) {
      S.wDrag = true;
      S.wPinch = false;
      S.wDs = { x: e.touches[0].clientX, y: e.touches[0].clientY };
      S.wPs = { ...S.wPan };
    } else if (e.touches.length === 2) {
      S.wDrag = false;
      S.wPinch = true;
      const dx = e.touches[0].clientX - e.touches[1].clientX;
      const dy = e.touches[0].clientY - e.touches[1].clientY;
      S.wPinchDist = Math.hypot(dx, dy);
      S.wPinchZoom = S.wZoom;
      // Pinch midpoint
      S.wPinchMid = {
        x: (e.touches[0].clientX + e.touches[1].clientX) / 2,
        y: (e.touches[0].clientY + e.touches[1].clientY) / 2,
      };
      S.wPinchPan = { ...S.wPan };
    }
  },
  { passive: true },
);

wC.addEventListener(
  "touchmove",
  (e) => {
    e.preventDefault();
    if (e.touches.length === 1 && S.wDrag && !S.wPinch) {
      const r = clampWPan(
        S.wPs.x + (e.touches[0].clientX - S.wDs.x),
        S.wPs.y + (e.touches[0].clientY - S.wDs.y),
        S.wZoom,
      );
      S.wPan = r;
      applyW();
    } else if (e.touches.length === 2 && S.wPinch) {
      const dx = e.touches[0].clientX - e.touches[1].clientX;
      const dy = e.touches[0].clientY - e.touches[1].clientY;
      const dist = Math.hypot(dx, dy);
      const scale = dist / S.wPinchDist;
      const cz = typeof coverZoom === "function" ? coverZoom() : 1;
      const nz = Math.max(cz, Math.min(4, S.wPinchZoom * scale));
      // Zoom toward pinch midpoint
      const mid = S.wPinchMid;
      const ix = (mid.x - S.wPinchPan.x) / S.wPinchZoom;
      const iy = (mid.y - S.wPinchPan.y) / S.wPinchZoom;
      S.wZoom = nz;
      S.wPan = clampWPan(mid.x - ix * nz, mid.y - iy * nz, nz);
      applyW();
    }
  },
  { passive: false },
);

wC.addEventListener("touchend", (e) => {
  if (e.touches.length === 0) {
    S.wDrag = false;
    S.wPinch = false;
  } else if (e.touches.length === 1) {
    S.wPinch = false;
    S.wDrag = true;
    S.wDs = { x: e.touches[0].clientX, y: e.touches[0].clientY };
    S.wPs = { ...S.wPan };
  }
});

/* ══ ENTER DISTRICT ══ */
function enterDistrict(d, evt) {
  S.activeD = d;
  const distIdx = DISTRICTS.indexOf(d);
  localStorage.setItem("lastDistIdx", distIdx);
  animZoomTo(d.px, d.py, 700);

  setTimeout(() => {
    flash();
    setTimeout(() => {
      toSc("worldScreen", "districtScreen");
      setupDistrict(d);

      const dInner = document.getElementById("dInner");
      if (dInner) {
        // 1. On retire la classe au cas où elle y soit déjà
        dInner.classList.remove("district-entrance-zoom");

        // 2. TRÈS IMPORTANT : on force un recalcul (reflow)
        // sans cette ligne, le "remove" et le "add" s'annulent
        void dInner.offsetWidth;

        // 3. On ajoute la classe pour lancer l'animation
        dInner.classList.add("district-entrance-zoom");

        // 4. On s'assure que le zoom part bien du centre
        dInner.style.transformOrigin = "center center";
      }
    }, 250);
  }, 700);
}
/* ══ DISTRICT VIEW ══ */
function setupDistrict(d, onReady) {
  // Set accent CSS var
  const accent = d.accent || "#e67e22";
  document.documentElement.style.setProperty("--accent", accent);

  // Title
  document.getElementById("dTitleIcon").textContent = d.emoji;
  document.getElementById("dTitleName").textContent = d.name;

  // District photo
  const img = document.getElementById("dPhoto");
  img.src = DIST_PHOTOS[d.id];
  img.onload = () => {
    S.dImgW = img.naturalWidth;
    S.dImgH = img.naturalHeight;
    // Fit image to screen on load
    const canvas = document.getElementById("dCanvas");
    const cz = Math.max(
      canvas.clientWidth / S.dImgW,
      canvas.clientHeight / S.dImgH,
    );
    S.dZoom = cz;
    S.dPan = { x: 0, y: 0 };
    document.getElementById("dInner").style.width = S.dImgW + "px";
    document.getElementById("dInner").style.height = S.dImgH + "px";
    document.getElementById("dInner").style.marginTop = -S.dImgH / 2 + "px";
    document.getElementById("dInner").style.marginLeft = -S.dImgW / 2 + "px";
    applyD();
    buildPins(d, onReady);
  };
  if (img.complete && img.naturalWidth) {
    img.onload();
  }

  // Close any open mini card
  closeMiniCard();

  // Show/hide locked overlay
  const overlay = document.getElementById("dOverlay");
  if (d.locked) {
    overlay.style.display = "flex";
  } else {
    overlay.style.display = "none";
  }
}

function applyD() {
  document.getElementById("dInner").style.transform =
    `translate(${S.dPan.x}px,${S.dPan.y}px) scale(${S.dZoom})`;
}
function clampDPan(x, y, z) {
  const c = document.getElementById("dCanvas");
  const sw = S.dImgW * z,
    sh = S.dImgH * z;
  const mx = Math.max(0, (sw - c.clientWidth) / 2),
    my = Math.max(0, (sh - c.clientHeight) / 2);
  return {
    x: Math.max(-mx, Math.min(mx, x)),
    y: Math.max(-my, Math.min(my, y)),
  };
}
function coverDZoom() {
  const c = document.getElementById("dCanvas");
  return Math.max(c.clientWidth / S.dImgW, c.clientHeight / S.dImgH);
}

function buildPins(d, onReady) {
  // Remove old pins
  document.querySelectorAll(".mpin").forEach((e) => e.remove());
  const markets = MARKETS[d.id] || [];
  const inner = document.getElementById("dInner");

  d.pins.forEach((pos, i) => {
    const mkt = markets[pos.mi];
    const pin = document.createElement("div");
    pin.className = "mpin";
    pin.style.cssText = `left:${pos.x}%;top:${pos.y}%;`;

    if (pos.locked) {
      pin.innerHTML =
        '<div class="mpin-label">قريباً</div>' +
        '<div class="mpin-bubble" style="opacity:1;">🔒</div>' +
        '<div class="mpin-tip"></div>';

      pin.onclick = (e) => {
        e.stopPropagation();
        openComingSoon();
      };
    } else if (!mkt) {
      pin.innerHTML =
        '<div class="mpin-label">' +
        (pos.name || "Market") +
        "</div>" +
        '<div class="mpin-bubble">' +
        d.emoji +
        "</div>" +
        '<div class="mpin-tip"></div>';
    } else {
      pin.innerHTML =
        '<div class="mpin-label">' +
        mkt.name +
        "</div>" +
        '<div class="mpin-bubble">' +
        d.emoji +
        "</div>" +
        '<div class="mpin-tip"></div>';
      pin.dataset.mktIdx = pos.mi;
      pin.addEventListener("click", (e) => {
        e.stopPropagation();
        selectPin(pin, mkt, d);
      });
    }

    pin.style.opacity = "0";
    pin.style.transform = "translate(-50%,-100%) translateY(10px)";
    inner.appendChild(pin);
    setTimeout(
      () => {
        pin.style.transition = "opacity .4s,transform .4s";
        pin.style.opacity = "1";
        pin.style.transform = "translate(-50%,-100%) translateY(0)";
      },
      100 + i * 120,
    );
  });

  // All pins appended to DOM — fire callback immediately
  if (typeof onReady === "function") onReady();
}

function selectPin(pin, mkt, d) {
  // Deselect all
  document
    .querySelectorAll(".mpin")
    .forEach((p) => p.classList.remove("selected"));
  pin.classList.add("selected");
  S.activeMkt = mkt;

  // Always sync the accent CSS variable so selected pin colors are correct
  const accent = d.accent || "#e67e22";
  document.documentElement.style.setProperty("--accent", accent);

  // Persist minicard state
  const distMarkets = MARKETS[d.id] || [];
  const mktIdx = distMarkets.indexOf(mkt);
  localStorage.setItem(
    "lastMarketId",
    JSON.stringify({ distId: d.id, mktIdx: mktIdx }),
  );
  localStorage.setItem("lastMiniCardOpen", "true");

  // Fill mini card
  document.getElementById("mcIcon").textContent = d.emoji;
  document.getElementById("mcIcon").style.background = accent + "22";
  document.getElementById("mcName").textContent = mkt.name;
  document.getElementById("mcSub").textContent = mkt.sub;
  document.getElementById("mcViewBtn").style.background = accent;
  openMiniCard();
}

function openMiniCard() {
  document.getElementById("miniCard").classList.add("open");
  document
    .querySelectorAll(".zoom-controls")
    .forEach((c) => c.classList.add("hidden"));
}
function closeMiniCard() {
  document.getElementById("miniCard").classList.remove("open");
  document
    .querySelectorAll(".zoom-controls")
    .forEach((c) => c.classList.remove("hidden"));
  document
    .querySelectorAll(".mpin")
    .forEach((p) => p.classList.remove("selected"));
  localStorage.removeItem("lastMiniCardOpen");
  localStorage.removeItem("lastMarketId");
}
function openComingSoon() {
  const o = document.getElementById("comingSoonOverlay");
  if (!o) return;
  o.classList.add("on");
  o.setAttribute("aria-hidden", "false");
}

function closeComingSoon() {
  const o = document.getElementById("comingSoonOverlay");
  if (!o) return;
  o.classList.remove("on");
  o.setAttribute("aria-hidden", "true");
}

// Close Coming Soon on backdrop click + ESC
document.addEventListener("click", (e) => {
  const o = document.getElementById("comingSoonOverlay");
  if (!o || !o.classList.contains("on")) return;
  if (e.target === o) closeComingSoon();
});
document.addEventListener("keydown", (e) => {
  if (e.key !== "Escape") return;
  const o = document.getElementById("comingSoonOverlay");
  if (!o || !o.classList.contains("on")) return;
  closeComingSoon();
});

// Tap background closes mini card
document.getElementById("dCanvas").addEventListener("click", (e) => {
  if (!e.target.closest(".mpin") && !e.target.closest("#miniCard"))
    closeMiniCard();
});

