/* ── Seen/unread helpers ── */
function _getSeenIds() {
  try {
    return new Set(JSON.parse(localStorage.getItem("newsSeenIds") || "[]"));
  } catch (e) {
    return new Set();
  }
}
function _saveSeenIds(set) {
  localStorage.setItem("newsSeenIds", JSON.stringify([...set]));
}
function _markAllSeen(source) {
  const seen = _getSeenIds();
  source.forEach((n) => seen.add(n.id));
  _saveSeenIds(seen);
  _updateUnreadDots();
}
function _hasUnread(source) {
  const seen = _getSeenIds();
  return source.some((n) => !seen.has(n.id));
}
function _updateUnreadDots() {
  const anyM = _hasUnread(NEWS_DATA);
  const anyS = _hasUnread(SYSTEM_DATA);
  const btn = document.getElementById("newsToggleBtn");
  if (btn) btn.classList.toggle("has-unread", anyM || anyS);
  const tabM = document.getElementById("newsTabMarket");
  const tabS = document.getElementById("newsTabSys");
  if (tabM) tabM.classList.toggle("has-unread", anyM);
  if (tabS) tabS.classList.toggle("has-unread", anyS);
}

/* ── Relative timestamp ── */
/* Rules:
      /* ── Case-insensitive district resolver ──
       * Matches districtId from news items against DISTRICTS regardless of casing.
       * e.g. "Sport", "SPORTS", "sports" all resolve to the same district object.
       */
function _findDistrict(districtId) {
  if (!districtId) return null;
  const lower = districtId.trim().toLowerCase();
  return DISTRICTS.find((d) => d.id.toLowerCase() === lower) || null;
}

/* ── Case-insensitive accent resolver for news cards ── */
function _districtAccent(districtId) {
  if (!districtId) return null;
  const lower = districtId.trim().toLowerCase();
  for (const key of Object.keys(DISTRICT_ACCENTS)) {
    if (key.toLowerCase() === lower) return DISTRICT_ACCENTS[key];
  }
  return null;
}

/* ── Relative timestamp ──
 *   item.published = "YYYY-MM-DD HH:mm"  (manually set by admin)
 *   - Same calendar day as today  →  relative  ("منذ X دقائق / ساعات")
 *   - A past calendar day         →  date only  ("DD/MM/YYYY")
 *   - No published field          →  item.date as-is
 */
function _timeAgo(item) {
  if (!item.published) return item.date || "";
  // Support both "YYYY-MM-DD HH:mm" and ISO strings
  const ts = new Date(item.published.replace(" ", "T"));
  if (isNaN(ts.getTime())) return item.date || item.published;
  // Build YYYY-M-D strings in local time for calendar-day comparison
  const now = new Date();
  const todayStr =
    now.getFullYear() + "-" + (now.getMonth() + 1) + "-" + now.getDate();
  const pubStr =
    ts.getFullYear() + "-" + (ts.getMonth() + 1) + "-" + ts.getDate();
  if (pubStr !== todayStr) {
    // Past day — date only, no time
    const d = String(ts.getDate()).padStart(2, "0");
    const m = String(ts.getMonth() + 1).padStart(2, "0");
    return d + "/" + m + "/" + ts.getFullYear();
  }
  // Same day — relative time
  const diffMin = Math.floor((now - ts) / 60000);
  const diffH = Math.floor(diffMin / 60);
  if (diffMin < 1) return "منذ لحظات";
  if (diffMin === 1) return "منذ دقيقة";
  if (diffMin === 2) return "منذ دقيقتين";
  if (diffMin <= 10) return "منذ " + diffMin + " دقائق";
  if (diffMin < 60) return "منذ " + diffMin + " دقيقة";
  if (diffH === 1) return "منذ ساعة";
  if (diffH === 2) return "منذ ساعتين";
  if (diffH <= 10) return "منذ " + diffH + " ساعات";
  return "منذ " + diffH + " ساعة";
}

function _renderMarketNews(container) {
  if (!NEWS_DATA || NEWS_DATA.length === 0) {
    container.innerHTML =
      '<div class="news-empty">' +
      '<span class="news-empty-icon">\u{1F4ED}</span>' +
      "<span>\u{0644}\u{0627} \u{062A}\u{0648}\u{062C}\u{062F} \u{0623}\u{062E}\u{0628}\u{0627}\u{0631} \u{062D}\u{0627}\u{0644}\u{064A}\u{0627}\u{064B}</span>" +
      "</div>";
    return;
  }
  const seen_m = _getSeenIds();
  const sorted_m = NEWS_DATA.slice().sort((a, b) => {
    const ta = a.published
      ? new Date(a.published.replace(" ", "T")).getTime()
      : 0;
    const tb = b.published
      ? new Date(b.published.replace(" ", "T")).getTime()
      : 0;
    return tb - ta;
  });
  container.innerHTML = sorted_m
    .map((item, idx) => {
      const isNew = !seen_m.has(item.id);
      const accent =
        _districtAccent(item.districtId) ||
        NEWS_ACCENTS[idx % NEWS_ACCENTS.length];
      const dist = _findDistrict(item.districtId);
      const markets = dist ? MARKETS[dist.id] || [] : [];
      const mkt = markets[item.marketIdx];
      const marketLabel = mkt ? mkt.name : dist ? dist.name : "";
      const distEmoji = dist ? dist.emoji : "\u{1F4CD}";
      const mapBtn =
        dist && mkt
          ? '<button class="news-map-btn" onclick="goToNewsMarket(\'' +
            item.id +
            "')\">\u{1F4CD} \u{0639}\u{0631}\u{0636} \u{0639}\u{0644}\u{0649} \u{0627}\u{0644}\u{062E}\u{0631}\u{064A}\u{0637}\u{0629}</button>"
          : "";
      const linkBtn = item.link
        ? '<a class="news-link-btn" href="' +
          item.link +
          '" target="_blank" rel="noopener"><i class="fa-solid fa-arrow-up-right-from-square"></i> \u{0631}\u{0627}\u{0628}\u{0637}</a>'
        : "";
      const newBadge_m = isNew
        ? '<span class="news-new-badge">جديد</span>'
        : "";
      return (
        '<div class="news-box' +
        (isNew ? " is-new" : "") +
        '" style="--news-accent:' +
        accent +
        '">' +
        newBadge_m +
        '<div class="news-inner">' +
        '<div class="news-meta">' +
        '<span class="news-cat">' +
        item.sub +
        "</span>" +
        '<span class="news-date">' +
        _timeAgo(item) +
        "</span>" +
        (marketLabel
          ? '<span class="news-market-tag">' +
            distEmoji +
            " " +
            marketLabel +
            "</span>"
          : "") +
        "</div>" +
        '<div class="news-box-title">' +
        item.title +
        "</div>" +
        '<div class="news-box-content">' +
        item.content +
        "</div>" +
        '<div class="news-actions">' +
        mapBtn +
        linkBtn +
        "</div>" +
        "</div></div>"
      );
    })
    .join("");
  setTimeout(() => _markAllSeen(NEWS_DATA), 1500);
}

function _renderSystemNews(container) {
  if (!SYSTEM_DATA || SYSTEM_DATA.length === 0) {
    container.innerHTML =
      '<div class="news-empty">' +
      '<span class="news-empty-icon">🔔</span>' +
      "<span>لا توجد إشعارات حالياً</span>" +
      "</div>";
    return;
  }
  // accent per type — drives both the left bar and badge bg
  const typeAccent = { update: "#5aad7a", notice: "#7aafc8", alert: "#c87941" };
  const seen_s = _getSeenIds();
  const sorted_s = SYSTEM_DATA.slice().sort((a, b) => {
    const ta = a.published
      ? new Date(a.published.replace(" ", "T")).getTime()
      : 0;
    const tb = b.published
      ? new Date(b.published.replace(" ", "T")).getTime()
      : 0;
    return tb - ta;
  });
  container.innerHTML = sorted_s
    .map((item) => {
      const isNew = !seen_s.has(item.id);
      const accent = typeAccent[item.type] || "#7aafc8";
      const newBadge_s = isNew
        ? '<span class="news-new-badge">جديد</span>'
        : "";
      return (
        '<div class="news-box sys-box' +
        (isNew ? " is-new" : "") +
        '" style="--news-accent:' +
        accent +
        '">' +
        newBadge_s +
        '<div class="news-inner">' +
        '<div class="news-meta">' +
        '<span class="news-cat">' +
        item.sub +
        "</span>" +
        '<span class="news-date">' +
        _timeAgo(item) +
        "</span>" +
        "</div>" +
        '<div class="news-box-title">' +
        item.title +
        "</div>" +
        '<div class="news-box-content">' +
        item.content +
        "</div>" +
        "</div></div>"
      );
    })
    .join("");
  setTimeout(() => _markAllSeen(SYSTEM_DATA), 1500);
}

function goToNewsMarket(newsId) {
  const item = NEWS_DATA.find((n) => n.id === newsId);
  if (!item) return;

  const dist = _findDistrict(item.districtId);
  if (!dist) return;
  const markets = MARKETS[dist.id] || [];
  const mkt = markets[item.marketIdx];
  if (!mkt) return;

  // Close news panel
  document.getElementById("newsPanel").classList.remove("open");

  S.activeD = dist;
  S.activeMkt = mkt;

  // Determine current screen
  const onWorld = !document
    .getElementById("worldScreen")
    .classList.contains("hidden");
  const onDistrict = !document
    .getElementById("districtScreen")
    .classList.contains("hidden");
  const onProfile = !document
    .getElementById("profileScreen")
    .classList.contains("hidden");

  if (onWorld) {
    toSc("worldScreen", "districtScreen");
  } else if (onProfile) {
    toSc("profileScreen", "districtScreen");
  } else if (!onDistrict) {
    // loginScreen or other — go to district directly
    document.getElementById("districtScreen").classList.remove("hidden");
    document.getElementById("loginScreen").classList.add("hidden");
  }

  // setupDistrict with onReady callback
  setupDistrict(dist, () => {
    // Fill and open minicard
    const _a = dist.accent || "#e67e22";
    document.getElementById("mcIcon").textContent = dist.emoji;
    document.getElementById("mcIcon").style.background = _a + "22";
    document.getElementById("mcName").textContent = mkt.name;
    document.getElementById("mcSub").textContent = mkt.sub;
    document.getElementById("mcViewBtn").style.background = _a;
    openMiniCard();

    // Highlight pin
    const markets2 = MARKETS[dist.id] || [];
    const mktIdx = markets2.indexOf(mkt);
    document
      .querySelectorAll(".mpin.search-found")
      .forEach((p) => p.classList.remove("search-found", "selected"));
    document.querySelectorAll(".mpin").forEach((pin) => {
      if (parseInt(pin.dataset.mktIdx) === mktIdx) {
        pin.classList.add("search-found", "selected");
        setTimeout(() => pin.classList.remove("search-found"), 4000);
      }
    });
  });
}

/* ════ WEATHER FX ENGINE ════ */
(function () {
  const WX = {
    canvas: null,
    ctx: null,
    raf: null,
    particles: [],
    type: "none", // none | rain | heavy-rain | storm | snow | fog | cloudy | clear
    W: 0,
    H: 0,
  };

  // Map WMO code → effect type
  function _codeToFx(code) {
    if ([0, 1].includes(code)) return "clear";
    if ([2, 3].includes(code)) return "cloudy";
    if ([45, 48].includes(code)) return "fog";
    if ([51, 53, 61, 63, 80, 81].includes(code)) return "rain";
    if ([55, 65, 82].includes(code)) return "heavy-rain";
    if ([95, 96, 99].includes(code)) return "storm";
    if ([71, 73, 77, 85].includes(code)) return "snow";
    if ([75, 86].includes(code)) return "heavy-snow";
    return "cloudy";
  }

  function _resize() {
    WX.W = WX.canvas.width = window.innerWidth;
    WX.H = WX.canvas.height = window.innerHeight;
  }

  function _spawnRain(n, heavy) {
    for (let i = 0; i < n; i++) {
      WX.particles.push({
        x: Math.random() * WX.W * 1.2 - WX.W * 0.1,
        y: Math.random() * WX.H,
        len: heavy ? 10 + Math.random() * 18 : 7 + Math.random() * 12,
        speed: heavy ? 14 + Math.random() * 10 : 9 + Math.random() * 7,
        alpha: heavy ? 0.35 + Math.random() * 0.3 : 0.2 + Math.random() * 0.25,
        angle: heavy ? 0.38 : 0.28, // radians from vertical
      });
    }
  }

  function _spawnSnow(n) {
    for (let i = 0; i < n; i++) {
      WX.particles.push({
        x: Math.random() * WX.W,
        y: Math.random() * WX.H,
        r: 1.5 + Math.random() * 2.5,
        speed: 0.6 + Math.random() * 1.2,
        drift: (Math.random() - 0.5) * 0.6,
        alpha: 0.55 + Math.random() * 0.35,
        phase: Math.random() * Math.PI * 2,
      });
    }
  }

  function _drawRain(heavy, storm) {
    const ctx = WX.ctx;
    ctx.clearRect(0, 0, WX.W, WX.H);

    // Lightning flash for storm
    if (storm && Math.random() < 0.003) {
      ctx.fillStyle = "rgba(200,220,255,0.08)";
      ctx.fillRect(0, 0, WX.W, WX.H);
    }

    for (const p of WX.particles) {
      const dx = Math.sin(p.angle) * p.len;
      const dy = Math.cos(p.angle) * p.len;
      ctx.beginPath();
      ctx.moveTo(p.x, p.y);
      ctx.lineTo(p.x + dx, p.y + dy);
      ctx.strokeStyle = "rgba(174,214,241," + p.alpha + ")";
      ctx.lineWidth = heavy ? 1.1 : 0.8;
      ctx.stroke();

      p.x += Math.sin(p.angle) * p.speed;
      p.y += Math.cos(p.angle) * p.speed;
      if (p.y > WX.H + 20 || p.x > WX.W + 20) {
        p.x = Math.random() * WX.W * 1.2 - WX.W * 0.1;
        p.y = -p.len;
      }
    }
  }

  function _drawSnow() {
    const ctx = WX.ctx;
    ctx.clearRect(0, 0, WX.W, WX.H);
    const t = Date.now() / 1000;
    for (const p of WX.particles) {
      p.x += p.drift + Math.sin(t + p.phase) * 0.3;
      p.y += p.speed;
      if (p.y > WX.H + 10) {
        p.y = -10;
        p.x = Math.random() * WX.W;
      }
      if (p.x > WX.W + 10) p.x = -10;
      if (p.x < -10) p.x = WX.W + 10;
      ctx.beginPath();
      ctx.arc(p.x, p.y, p.r, 0, Math.PI * 2);
      ctx.fillStyle = "rgba(255,255,255," + p.alpha + ")";
      ctx.fill();
    }
  }

  function _loop() {
    if (WX.type === "rain") {
      _drawRain(false, false);
    } else if (WX.type === "heavy-rain") {
      _drawRain(true, false);
    } else if (WX.type === "storm") {
      _drawRain(true, true);
    } else if (WX.type === "snow" || WX.type === "heavy-snow") {
      _drawSnow();
    } else {
      WX.ctx.clearRect(0, 0, WX.W, WX.H);
    }
    WX.raf = requestAnimationFrame(_loop);
  }

  function _applyClasses(type) {
    const el = document.getElementById("weatherFX");
    el.classList.remove(
      "active",
      "fog-active",
      "overcast-active",
      "storm-active",
    );
    if (type === "none" || type === "clear") return;
    el.classList.add("active");
    if (type === "fog") el.classList.add("fog-active");
    if (type === "cloudy") el.classList.add("overcast-active");
    if (type === "storm") el.classList.add("storm-active", "overcast-active");
    if (type === "rain" || type === "heavy-rain")
      el.classList.add("overcast-active");
    if (type === "snow" || type === "heavy-snow")
      el.classList.add("overcast-active");
  }

  window.applyWeatherFX = function (code) {
    const type = _codeToFx(code);
    if (WX.type === type) return;
    WX.type = type;
    WX.particles = [];
    WX.ctx.clearRect(0, 0, WX.W, WX.H);

    if (type === "rain") _spawnRain(120, false);
    else if (type === "heavy-rain") _spawnRain(220, true);
    else if (type === "storm") _spawnRain(280, true);
    else if (type === "snow") _spawnSnow(100);
    else if (type === "heavy-snow") _spawnSnow(180);

    _applyClasses(type);
  };

  // Init on DOM ready
  document.addEventListener("DOMContentLoaded", function () {
    WX.canvas = document.getElementById("weatherCanvas");
    WX.ctx = WX.canvas.getContext("2d");
    _resize();
    window.addEventListener("resize", _resize);
    _loop();
  });
})();

// Hide cs button when miniCard is open so it doesn't overlap
(function () {
  document.addEventListener("DOMContentLoaded", function () {
    const btn = document.getElementById("csBtn");
    const tooltip = document.getElementById("csTooltip");
    const mc = document.getElementById("miniCard");
    const dot = document.querySelector(".cst-dot");
    if (!btn || !mc) return;

    function refreshCsStatus() {
      const now = new Date();
      const day = now.getDay();
      const minutes = now.getHours() * 60 + now.getMinutes();
      const isOpenDay = day !== 5; // Closed on Friday
      const isOpenTime = minutes >= 9 * 60 && minutes < 16 * 60;
      const isOpen = isOpenDay && isOpenTime;

      btn.classList.toggle("cs-closed", !isOpen);
      if (dot) dot.classList.toggle("hidden", !isOpen);
    }
    refreshCsStatus();
    setInterval(refreshCsStatus, 60 * 1000);

    // Toggle tooltip on click
    btn.addEventListener("click", function (e) {
      e.stopPropagation();
      tooltip.classList.toggle("open");
    });
    // Close tooltip when clicking elsewhere
    document.addEventListener("click", function () {
      tooltip.classList.remove("open");
    });

    // Hide button when miniCard slides up
    const obs = new MutationObserver(function () {
      if (mc.classList.contains("open")) {
        btn.classList.add("hidden-by-card");
        tooltip.classList.remove("open");
      } else {
        btn.classList.remove("hidden-by-card");
      }
    });
    obs.observe(mc, { attributes: true, attributeFilter: ["class"] });
  });
})();

